import pickle
import os
from datetime import datetime
from functools import wraps

class Cache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)

    def serialize(self, data):
        return pickle.dumps(data)

    def deserialize(self, serialized_data):
        try:
            return pickle.loads(serialized_data)
        except Exception as e:
            print(f"Error deserializing: {e}")
            return None

    def cache_get(self, key):
        file_path = os.path.join(self.cache_dir, f"{key}.bin")
        if os.path.exists(file_path):
            with open(file_path, "rb") as f:
                serialized_data = f.read()
                data = self.deserialize(serialized_data)
                return data
        return None

    def cache_set(self, key, value, expire_hours=24):
        file_path = os.path.join(self.cache_dir, f"{key}.bin")
        with open(file_path, "wb") as f:
            serialized_data = self.serialize(value)
            f.write(serialized_data)

        # Set expiration
        expire_at = datetime.now() + datetime.timedelta(hours=expire_hours)
        with open(f"{file_path}.exp", "w") as f:
            f.write(str(expire_at.timestamp()))

    def cache_is_expired(self, key):
        file_path = os.path.join(self.cache_dir, f"{key}.bin")
        expire_file_path = f"{file_path}.exp"
        if not os.path.exists(expire_file_path):
            return False
        with open(expire_file_path, "r") as f:
            expire_at_timestamp = float(f.read())
            if datetime.now().timestamp() < expire_at_timestamp:
                return False
        return True

def cached_api_response(func):
    cache = Cache("/tmp/cache")
    @wraps(func)
    def wrapper(*args, **kwargs):
        key = str(args) + str(kwargs)
        data = cache.cache_get(key)
        if data is not None and not cache.cache_is_expired(key):
            return data
        else:
            response = func(*args, **kwargs)
            cache.cache_set(key, response)
            return response
    return wrapper

